sql:
SELECT title_type, primary_title, start_year
FROM titles
WHERE average_rating > (SELECT AVG(average_rating) FROM titles);

SELECT primary_title 
FROM titles 
WHERE title_type = 'movie' AND start_year < 1960;

SELECT tconst, primary_title
FROM titles
WHERE average_rating > 7 AND num_votes > 100;

SELECT DISTINCT tconst
FROM user_ratings
WHERE rating > 8;

SELECT title_type, SUM(num_votes) AS total_votes
FROM titles
GROUP BY title_type;

SELECT COUNT(*) 
FROM titles 
WHERE title_type = 'movie' AND start_year > 2000;

SELECT SUM(won) AS total_awards_won
FROM title_awards
WHERE category = 'Best Director';

external_knowledge:
- 'cinematic treasures' refers to movies;
- 'creators' refers to users with the role 'content creator';
- 'whispers of their average praise' refers to the average rating of the movies;
- 'whispered by at least three voices' means there must be at least three ratings for each movie.
